var g_iRtspPort2 = 554;
var g_iWndIndex2 = 0;
var g_iWebSocketPort = 7681;
var g_iWndIndex = 0;
var g_iChannelList = [];
var g_iChannelID = 1;
var g_iChannelID = 1;
var connectedDevice = null;
// WASM SDK global functions (simple version)
function setLoginStatus(msg, color) {
    var el = document.getElementById('login-status');
    if (el) {
        el.textContent = msg;
        if (color) el.style.color = color;
    }
    console.log('[WASM] Status: ' + msg);
}
function clickLogin2() {
    console.log('[CLICKLOGIN2] Called');
    if (!window.connectedDevice || !window.connectedDevice.ip) {
        console.log('[WASM SDK] No device connected');
        return;
    }
    console.log('[CLICKLOGIN2] Device IP: ' + window.connectedDevice.ip);
    var szIP = window.connectedDevice.ip;
    var szPort = window.connectedDevice.port || 80;
    var szUsername = window.connectedDevice.username || 'admin';
    var szPassword = window.connectedDevice.password || '';
    g_szDeviceIdentify2 = szIP + '_' + szPort;
    console.log('[WASM SDK] Login: ' + szIP + ':' + szPort);
    WebVideoCtrl.I_Login(szIP, 1, szPort, szUsername, szPassword, {
        timeout: 5000,
        success: function(xmlDoc) {
            g_bLoggedIn2 = true;
            console.log('[WASM SDK] Login success: ' + g_szDeviceIdentify2);
            // I_GetDevicePort is SYNCHRONOUS - no .then() needed
                var oPort = WebVideoCtrl.I_GetDevicePort(g_szDeviceIdentify2);
                console.log('[WASM SDK] GetDevicePort result:', oPort);
                if (oPort) {
                    g_iRtspPort2 = oPort.iRtspPort || 554;
                    console.log('[WASM SDK] RTSP port:', g_iRtspPort2);
                }
                // Start stream after short delay
                console.log('[WASM SDK] Calling startConsoleStream2 in 200ms...');
                setTimeout(function() {
                    console.log('[WASM SDK] setTimeout fired, startConsoleStream2 exists:', typeof window.startConsoleStream2);
                    if (window.startConsoleStream2) {
                        window.startConsoleStream2('sub');
                    } else {
                        console.error('[WASM SDK] startConsoleStream2 not found!');
                    }
                }, 200);
        },
        error: function(status, xmlDoc) {
            console.error('[WASM SDK] Login failed:', status);
            g_bLoggedIn2 = false;
        }
    });
}
window.clickLogin2 = clickLogin2; // Manually expose to window
function startConsoleStream2(mode) {
    console.log("[STARTSTREAM2] Called, g_bLoggedIn2=", g_bLoggedIn2);
    if (!window.connectedDevice || !window.connectedDevice.ip) { console.log("[STARTSTREAM2] No device"); return; }
    if (!g_bLoggedIn2) { if (window.clickLogin2) window.clickLogin2(); return; }
    var iStreamType = (mode === 'main') ? 1 : 2;
    var oWndInfo = WebVideoCtrl.I_GetWindowStatus(g_iWndIndex2);
    var doStart = function() {
        console.log('[WASM SDK] Starting real play, stream=' + iStreamType);
        WebVideoCtrl.I_StartRealPlay(g_szDeviceIdentify2, {
            // iRtspPort not needed for WASM WebSocket mode
            iStreamType: iStreamType,
            iChannelID: 1,
            bZeroChannel: false,
            success: function() {
                g_bPlaying2 = true;
                console.log('[WASM SDK] Real play started');
            },
            error: function(status, xmlDoc) {
                console.error('[WASM SDK] StartRealPlay error:', status);
            }
        });
    };
    if (oWndInfo != null) {
        WebVideoCtrl.I_Stop({ success: function() { doStart(); }, error: function() { doStart(); } });
    } else {
        doStart();
    }
}
window.startConsoleStream2 = startConsoleStream2; // Manually expose
        function stopConsoleStream2() {
    if (!g_bPlaying2) return;
    var oWndInfo = WebVideoCtrl.I_GetWindowStatus(g_iWndIndex2);
    if (oWndInfo != null) {
        WebVideoCtrl.I_Stop({ success: function() { g_bPlaying2 = false; console.log('[WASM SDK] Stopped'); } });
    }
}

</script>

