```javascript
function connectDevice(ip) {
    addLog('info', '正在连接设备: ' + ip);
    // 先获取 credentials
    apiGet('/api/v1/ptz/devices/' + ip + '/credentials').then(function(creds) {
        var username = (creds && creds.success) ? creds.username : 'admin';
        var password = (creds && creds.success) ? creds.password : '';
        var port = (creds && creds.success) ? (creds.port || 80) : 80;

        // 再调用 connect API
        apiPost('/api/v1/devices/' + ip + '/connect', { username: username, password: password, port: port }).then(function(result) {
            if (result && result.success) {
                showToast('success', '设备已连接: ' + ip);
                addLog('success', result.message || '连接成功');
                refreshDevices();
                refreshPtzDeviceList();
                refreshAdvancedDeviceSelectors();
                // Update global window.connectedDevice
                var dev = allDevices.find(function(d) { return d.ip === ip; });
                if (dev) {
                    window.connectedDevice = {
                        ip: dev.ip, model: dev.model || '', name: dev.name || dev.device_name || '',
                        mac: dev.mac || '', username: username, password: password, port: port, online: true
                    };
                    addLog('info', '已记住连接设备: ' + window.connectedDevice.ip);
                    // WASM SDK login
                    if (window.clickLogin2) { window.clickLogin2(); }
                }
            } else if (result && result.message && result.message.indexOf('凭证') >= 0) {
                // credentials 错误，提示用户输入
                var username2 = prompt("请输入用户名:", "admin");
                if (!username2) return;
                var password2 = prompt("请输入密码:");
                if (!password2) return;
                connectDeviceWithCreds(ip, username2, password2, 80);
            } else {
                showToast('error', result ? result.message : '连接失败');
                addLog('error', result ? result.message : '连接失败');
            }
        }).catch(function(e) {
            showToast('error', '连接异常: ' + e.message);
            addLog('error', '连接异常: ' + e.message);
        });
    }).catch(function(e) {
        // credentials API 失败，尝试无密码连接
        apiPost('/api/v1/devices/' + ip + '/connect', null).then(function(result) {
            if (result && result.success) {
                showToast('success', '设备已连接: ' + ip);
                refreshDevices();
                refreshPtzDeviceList();
                refreshAdvancedDeviceSelectors();
                var dev = allDevices.find(function(d) { return d.ip === ip; });
                if (dev) {
                    window.connectedDevice = {
                        ip: dev.ip, model: dev.model || '', name: dev.name || dev.device_name || '',
                        mac: dev.mac || '', username: 'admin', password: '', port: 80, online: true
                    };
                    if (window.clickLogin2) { window.clickLogin2(); }
                }
            } else {
                showToast('error', result ? result.message : '连接失败');
            }
        });
    });
}
```

