import asyncio
from playwright.async_api import async_playwright

async def test():
    async with p.chromium.launch(headless=False) as browser:
        page = await browser.new_page()
        logs = []
        page.on('console', lambda msg: logs.append(msg.text))
        page.on('response', lambda resp: print(f'[NET] {resp.status} {resp.url[:60]}') if 'connect' in resp.url.lower() else None)

        await page.goto('http://localhost:10280', wait_until='networkidle')
        await asyncio.sleep(3)

        # Go to devices tab
        await page.click("[data-page='devices']")
        await asyncio.sleep(2)

        # Check device table
        rows = await page.locator('#deviceTable tr').count()
        print(f'[1] Device rows: {rows}')

        # Click connect button directly by onclick
        try:
            await page.evaluate('''() => {
                var btns = document.querySelectorAll('.btn-primary');
                for (var b of btns) {
                    if (b.textContent.includes('连接')) {
                        b.click();
                        return 'clicked';
                    }
                }
                return 'not found';
            }''')
            print('[2] Clicked connect via evaluate')
        except Exception as e:
            print(f'[2] Error: {e}')

        await asyncio.sleep(10)

        # Check connectedDevice
        state = await page.evaluate('''() => ({
            connectedDevice: window.connectedDevice,
            allDevices: window.allDevices,
            g_bLoggedIn2: window.g_bLoggedIn2
        })''')
        print(f'[3] State: connectedDevice={state["connectedDevice"]}, devices={len(state["allDevices"]) if state["allDevices"] else 0}')

        # WASM logs
        wasm_logs = [l for l in logs if 'Login' in l or 'SDK' in l or 'connect' in l.lower()]
        print('[4] Relevant logs:')
        for l in wasm_logs[-10:]:
            print(f'  {l}')

        await browser.close()

asyncio.run(test())

