import asyncio
from playwright.async_api import async_playwright

async def test():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=False)
        page = await browser.new_page()

        # 拦截 WASM 请求
        requests = []
        page.on('request', lambda req: requests.append({
            'url': req.url,
            'method': req.method
        }) if 'sessionLogin' in req.url or '192.168' in req.url else None)

        await page.goto('http://localhost:10280', wait_until='networkidle')
        await asyncio.sleep(3)

        # 设置 connectedDevice 并手动调用 login
        result = await page.evaluate('''async () => {
            window.connectedDevice = {
                ip: '192.168.5.72',
                port: 80,
                username: 'admin',
                password: 'Nftw1357',
                online: true
            };
            console.log('[TEST] Calling I_Login...');
            return new Promise((resolve) => {
                WebVideoCtrl.I_Login('192.168.5.72', 1, 80, 'admin', 'Nftw1357', {
                    timeout: 10000,
                    success: () => resolve({success: true}),
                    error: (s) => resolve({success: false, status: s})
                });
            });
        }''')

        await asyncio.sleep(5)

        print(f'Result: {result}')
        print('WASM requests:')
        for r in requests:
            print(f'  {r["method"]} {r["url"]}')

        await browser.close()

asyncio.run(test())
